// Funções auxiliares de parse e formatação
function parseField(val) {
  if (!val) return null;
  if (val.nullValue !== undefined) return null;
  if (val.stringValue !== undefined) return val.stringValue;
  if (val.integerValue !== undefined) return parseInt(val.integerValue, 10);
  if (val.doubleValue !== undefined) return parseFloat(val.doubleValue);
  if (val.booleanValue !== undefined) return val.booleanValue;
  if (val.timestampValue !== undefined) return val.timestampValue;
  if (val.mapValue) {
    const obj = {};
    for (const [k, v] of Object.entries(val.mapValue.fields || {})) {
      obj[k] = parseField(v);
    }
    return obj;
  }
  if (val.arrayValue) {
    return (val.arrayValue.values || []).map(parseField);
  }
  return null;
}

function parseDoc(doc) {
  const id = (doc.name || '').split('/').pop();
  const fields = {};
  for (const [k, v] of Object.entries(doc.fields || {})) {
    fields[k] = parseField(v);
  }
  return { id, ...fields };
}

function parseDateBR(str) {
  if (!str || typeof str !== 'string') return null;
  const br = str.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (br) {
    const [, d, m, y] = br;
    return new Date(`${y}-${m}-${d}T00:00:00Z`);
  }
  const iso = new Date(str);
  if (!isNaN(iso.getTime())) return iso;
  return null;
}

function diffDays(fromDate, toDate) {
  const ms = toDate.getTime() - fromDate.getTime();
  return Math.ceil(ms / (1000 * 60 * 60 * 24));
}

function normalizeText(str) {
  return String(str || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim().toLowerCase();
}

// 1. CAPTURA DOS NÓS HTTP (Com safe navigation para evitar crash se vier vazio)
const lotesDocs = $('Lotes').first()?.json?.documents || [];
const limitesDocs = $('Limites').first()?.json?.documents || [];
const catalogoDocs = $('Catalogo').first()?.json?.documents || [];
const alertasDocs = $('Alertas').first()?.json?.documents || []; 
const tarefasDocs = $('Tarefas').first()?.json?.documents || [];

const lotesRaw = lotesDocs.map(parseDoc);
const limitesRaw = limitesDocs.map(parseDoc);
const catalogoRaw = catalogoDocs.map(parseDoc);
const alertasRaw = alertasDocs.map(parseDoc);
const tarefasRaw = tarefasDocs.map(parseDoc);

// Ajustado para pegar a data atual dinamicamente em vez de fixar em maio
const hoje = new Date(); 

// 1.5 MAPEAMENTO DAS TAREFAS PENDENTES
const lotesEmAndamento = new Set();
const produtosEmAndamento = new Set();

tarefasRaw.forEach(tarefa => {
  const statusTarefa = normalizeText(tarefa.status || '');

  if (statusTarefa.includes('pendente')) {
    if (tarefa.loteId) lotesEmAndamento.add(tarefa.loteId);
    if (tarefa.loteAlvo) lotesEmAndamento.add(tarefa.loteAlvo); 
    if (tarefa.produtoAlvo) produtosEmAndamento.add(tarefa.produtoAlvo);
    if (tarefa.produtoId) produtosEmAndamento.add(tarefa.produtoId); 
  }
});

// 2. PROCESSAMENTO DOS LOTES E SENSORES
const lotesAtivos = lotesRaw
  .filter(l => normalizeText(l.status) === 'ativo')
  .map(l => {
    const validadeDate = parseDateBR(l.validade || l.dataValidade);
    return {
      id: l.id,
      item: l.item || null,
      pesoKg: typeof l.pesoKg === 'number' ? l.pesoKg : Number(l.pesoKg || 0),
      masterLote: l.masterLote || null,
      diasParaVencer: validadeDate ? diffDays(hoje, validadeDate) : null
    };
  });

const alertasSensoresPendentes = alertasRaw
  .filter(a => normalizeText(a.status) === 'pendente')
  .map(a => ({
    id: a.id,
    tipo: a.tipoAlerta || 'Infraestrutura',
    descricao: a.descricao,
    severidade: a.severidade
  }));

const limites = {};
for (const l of limitesRaw) {
  limites[l.id] = { min: Number(l.min || 0), max: Number(l.max || 0) };
}

const catalogo = {};
for (const c of catalogoRaw) {
  catalogo[c.id] = c.nome || c.id;
}

// 3. MATEMÁTICA DE ESTOQUE E PREVISÃO
const estoqueAtual = {};
for (const lote of lotesAtivos) {
  const produtoNome = normalizeText(lote.item);
  if (!estoqueAtual[produtoNome]) estoqueAtual[produtoNome] = 0;
  estoqueAtual[produtoNome] += lote.pesoKg;
}

let alertasPreditivos = [];
for (const [idProduto, configLimite] of Object.entries(limites)) {
  const nomeCatalogo = catalogo[idProduto] || idProduto;
  const nomeNormalizado = normalizeText(nomeCatalogo);
  const pesoAtual = estoqueAtual[nomeNormalizado] || 0;

  const consumoDiarioEstimado = (configLimite.max * 0.05) || 5; 
  const diasAteZerar = pesoAtual > 0 ? Math.floor(pesoAtual / consumoDiarioEstimado) : 0;

  if (diasAteZerar <= 7 || pesoAtual < configLimite.min) {
    alertasPreditivos.push({
      produtoId: idProduto,
      produto: nomeCatalogo,
      pesoAtualKg: pesoAtual,
      diasAteZerar: diasAteZerar,
      status: diasAteZerar <= 0 ? 'ZERADO' : 'RISCO DE RUPTURA'
    });
  }
}

// 4. SEPARAÇÃO DE URGÊNCIAS
let lotesDescarteImediato = lotesAtivos
  .filter(l => l.diasParaVencer !== null && l.diasParaVencer < 0)
  .map(l => ({ 
      item: l.item, 
      loteId: l.masterLote || l.id, 
      diasParaVencer: l.diasParaVencer
  }));

// 5. ESTOQUE GERAL (Onde a IA vai ler os limites Reais)
const estoqueGeral = {};
for (const [idProduto, configLimite] of Object.entries(limites)) {
  const nomeCatalogo = catalogo[idProduto] || idProduto;
  const nomeNormalizado = normalizeText(nomeCatalogo);

  estoqueGeral[nomeNormalizado] = {
    atualKg: estoqueAtual[nomeNormalizado] || 0,
    min: configLimite.min,
    max: configLimite.max
  };
}

// 6. RETORNO ÚNICO COMPRIMIDO PARA A IA
return [
  {
    json: {
      visaoGeral: {
        totalLotesAtivos: lotesAtivos.length,
        alertasEstoque: alertasPreditivos.length,
        lotesVencidos: lotesDescarteImediato.length,
        alertasInfraestrutura: alertasSensoresPendentes.length,
        tarefasOperacionaisPendentes: lotesEmAndamento.size + produtosEmAndamento.size
      },
      estoqueGeral,
      alertasPreditivos,
      lotesDescarteImediato,
      alertasSensoresPendentes
    }
  }
];
